    """
    Returns the contrast ratio of a given color.
    """
    import requests
    from colorsys import rgb_to_hls
    from re import search

    def get_color_code(color: str) -> tuple:
        match = search(r'rgb\((\d+), (\d+), (\d+)\)', color)
        if match:
            return tuple(int(match.group(i)) for i in range(1, 4))
        return 0, 0, 0

    def calculate_contrast_ratio(color1: tuple, color2: tuple) -> float:
        lum1 = 0.2126 * color1[0] / 255 + 0.7152 * color1[1] / 255 + 0.0722 * color1[2] / 255
        lum2 = 0.2126 * color2[0] / 255 + 0.7152 * color2[1] / 255 + 0.0722 * color2[2] / 255
        return (lum1 + 0.05) / (lum2 + 0.05) if lum1 > lum2 else (lum2 + 0.05) / (lum1 + 0.05)

    try:
        color1, color2 = query.split(' to ')
        color1, color2 = get_color_code(color1), get_color_code(color2)
        ratio = calculate_contrast_ratio(color1, color2)
        return f'Contrast ratio between {query} is {ratio:.2f}'
    except Exception as e:
        return f'Error: {str(e)}'

